// DApp Smart Contract Interaction Module
// Uses ethers.js for blockchain interaction with secure transaction handling

const { ethers } = require('ethers');
const readline = require('readline');

// ============================================
// Security: Input Validation & Sanitization
// ============================================

class InputValidator {
    static isValidAddress(address) {
        try {
            ethers.utils.getAddress(address);
            return true;
        } catch {
            return false;
        }
    }

    static isValidUint256(value) {
        try {
            const bn = ethers.BigNumber.from(value);
            return bn.gte(0) && bn.lte(ethers.constants.MaxUint256);
        } catch {
            return false;
        }
    }

    static isValidFunctionName(name) {
        // Only allow alphanumeric and underscores for function names
        return /^[a-zA-Z_][a-zA-Z0-9_]*$/.test(name);
    }

    static sanitizeString(input) {
        if (typeof input !== 'string') return '';
        // Remove control characters and limit length
        return input.replace(/[\x00-\x1f\x7f]/g, '').trim().substring(0, 1000);
    }

    static validateABI(abi) {
        if (!Array.isArray(abi)) return false;
        for (const item of abi) {
            if (typeof item !== 'object' || item === null) return false;
            if (item.type === 'function' && !this.isValidFunctionName(item.name)) {
                return false;
            }
        }
        return true;
    }

    static isValidChainId(chainId) {
        const id = parseInt(chainId, 10);
        return Number.isInteger(id) && id > 0 && id < 2147483647;
    }

    static validateGasLimit(gasLimit) {
        const bn = ethers.BigNumber.from(gasLimit);
        // Reasonable gas limit range: 21000 to 30,000,000
        return bn.gte(21000) && bn.lte(30000000);
    }

    static validateEtherValue(value) {
        try {
            const parsed = ethers.utils.parseEther(value);
            // Prevent excessively large values (e.g., > 1,000,000 ETH)
            return parsed.gte(0) && parsed.lte(ethers.utils.parseEther('1000000'));
        } catch {
            return false;
        }
    }
}

// ============================================
// Rate Limiter for Transaction Submission
// ============================================

class RateLimiter {
    constructor(maxRequests = 5, windowMs = 60000) {
        this.maxRequests = maxRequests;
        this.windowMs = windowMs;
        this.requests = [];
    }

    canProceed() {
        const now = Date.now();
        this.requests = this.requests.filter(t => now - t < this.windowMs);
        if (this.requests.length >= this.maxRequests) {
            return false;
        }
        this.requests.push(now);
        return true;
    }

    getWaitTime() {
        if (this.requests.length < this.maxRequests) return 0;
        const oldest = this.requests[0];
        return this.windowMs - (Date.now() - oldest);
    }
}

// ============================================
// Transaction Logger for Audit Trail
// ============================================

class TransactionLogger {
    constructor() {
        this.logs = [];
    }

    log(entry) {
        const logEntry = {
            timestamp: new Date().toISOString(),
            ...entry,
            // Never log private keys or sensitive data
        };
        this.logs.push(logEntry);
        console.log(`[TX LOG] ${JSON.stringify(logEntry, null, 2)}`);
    }

    getLogs() {
        return [...this.logs];
    }
}

// ============================================
// Allowlist for Contracts and Functions
// ============================================

class ContractAllowlist {
    constructor() {
        // Allowlisted contract addresses (lowercase)
        this.allowedContracts = new Map();
        // Allowlisted function selectors per contract
        this.allowedFunctions = new Map();
    }

    addContract(address, name, allowedFunctions = []) {
        const normalized = address.toLowerCase();
        this.allowedContracts.set(normalized, { name, addedAt: Date.now() });
        if (allowedFunctions.length > 0) {
            this.allowedFunctions.set(normalized, new Set(allowedFunctions));
        }
    }

    isContractAllowed(address) {
        return this.allowedContracts.has(address.toLowerCase());
    }

    isFunctionAllowed(address, functionName) {
        const normalized = address.toLowerCase();
        const functions = this.allowedFunctions.get(normalized);
        if (!functions) return true; // If no function restrictions, allow all
        return functions.has(functionName);
    }
}

// ============================================
// Secure Wallet Connection Manager
// ============================================

class WalletManager {
    constructor(providerUrl, chainId) {
        if (!providerUrl || typeof providerUrl !== 'string') {
            throw new Error('Invalid provider URL');
        }
        if (!InputValidator.isValidChainId(chainId)) {
            throw new Error('Invalid chain ID');
        }

        this.provider = new ethers.providers.JsonRpcProvider(providerUrl);
        this.expectedChainId = parseInt(chainId, 10);
        this.signer = null;
        this.address = null;
    }

    // Connect using a browser wallet (MetaMask-style) - for browser environments
    async connectBrowserWallet(windowEthereum) {
        if (!windowEthereum) {
            throw new Error('No browser wallet detected');
        }

        const provider = new ethers.providers.Web3Provider(windowEthereum);
        await provider.send('eth_requestAccounts', []);

        // Verify chain ID
        const network = await provider.getNetwork();
        if (network.chainId !== this.expectedChainId) {
            throw new Error(
                `Wrong network. Expected chain ID ${this.expectedChainId}, got ${network.chainId}`
            );
        }

        this.provider = provider;
        this.signer = provider.getSigner();
        this.address = await this.signer.getAddress();

        console.log(`Connected wallet: ${this.address}`);
        return this.address;
    }

    // Connect using environment variable private key (for server/CLI environments)
    // SECURITY: Private key is read from environment variable, never from user input
    async connectFromEnvironment() {
        const privateKey = process.env.DAPP_PRIVATE_KEY;
        if (!privateKey) {
            throw new Error(
                'DAPP_PRIVATE_KEY environment variable not set. ' +
                'Set it securely before running this application.'
            );
        }

        // Validate private key format
        if (!/^0x[0-9a-fA-F]{64}$/.test(privateKey)) {
            throw new Error('Invalid private key format in environment variable');
        }

        // Verify chain ID
        const network = await this.provider.getNetwork();
        if (network.chainId !== this.expectedChainId) {
            throw new Error(
                `Wrong network. Expected chain ID ${this.expectedChainId}, got ${network.chainId}`
            );
        }

        this.signer = new ethers.Wallet(privateKey, this.provider);
        this.address = await this.signer.getAddress();

        console.log(`Connected wallet: ${this.address}`);
        return this.address;
    }

    getSigner() {
        if (!this.signer) {
            throw new Error('Wallet not connected');
        }
        return this.signer;
    }

    getAddress() {
        if (!this.address) {
            throw new Error('Wallet not connected');
        }
        return this.address;
    }
}

// ============================================
// Smart Contract Interaction Manager
// ============================================

class ContractInteractionManager {
    constructor(walletManager, allowlist, logger) {
        this.walletManager = walletManager;
        this.allowlist = allowlist;
        this.logger = logger || new TransactionLogger();
        this.rateLimiter = new RateLimiter(10, 60000); // 10 tx per minute
        this.contracts = new Map();
        this.nonceLock = false;
    }

    // Register a contract with its ABI
    registerContract(name, address, abi) {
        if (!InputValidator.isValidAddress(address)) {
            throw new Error(`Invalid contract address: ${address}`);
        }
        if (!InputValidator.validateABI(abi)) {
            throw new Error('Invalid ABI format');
        }
        if (!this.allowlist.isContractAllowed(address)) {
            throw new Error(`Contract ${address} is not in the allowlist`);
        }

        const signer = this.walletManager.getSigner();
        const contract = new ethers.Contract(address, abi, signer);

        this.contracts.set(name, {
            contract,
            address,
            abi,
            interface: new ethers.utils.Interface(abi)
        });

        this.logger.log({
            action: 'CONTRACT_REGISTERED',
            name,
            address
        });

        console.log(`Contract "${name}" registered at ${address}`);
        return contract;
    }

    // Get registered contract
    getContract(name) {
        const entry = this.contracts.get(name);
        if (!entry) {
            throw new Error(`Contract "${name}" not registered`);
        }
        return entry;
    }

    // Build a transaction without sending (for review)
    async buildTransaction(contractName, functionName, params = [], overrides = {}) {
        const { contract, address, interface: iface } = this.getContract(contractName);

        // Validate function name
        if (!InputValidator.isValidFunctionName(functionName)) {
            throw new Error(`Invalid function name: ${functionName}`);
        }

        // Check function allowlist
        if (!this.allowlist.isFunctionAllowed(address, functionName)) {
            throw new Error(`Function "${functionName}" is not allowed for contract at ${address}`);
        }

        // Verify function exists in ABI
        const fragment = iface.getFunction(functionName);
        if (!fragment) {
            throw new Error(`Function "${functionName}" not found in contract ABI`);
        }

        // Validate parameter count
        if (params.length !== fragment.inputs.length) {
            throw new Error(
                `Expected ${fragment.inputs.length} parameters for "${functionName}", got ${params.length}`
            );
        }

        // Validate and sanitize parameters based on ABI types
        const validatedParams = this._validateParams(fragment.inputs, params);

        // Build transaction data
        const data = iface.encodeFunctionData(functionName, validatedParams);

        // Construct transaction object
        const tx = {
            to: address,
            data,
            ...this._buildOverrides(overrides)
        };

        // Estimate gas if not provided
        if (!tx.gasLimit) {
            try {
                const estimatedGas = await this.walletManager.getSigner().estimateGas(tx);
                // Add 20% buffer to gas estimate
                tx.gasLimit = estimatedGas.mul(120).div(100);
            } catch (error) {
                throw new Error(`Gas estimation failed: ${error.message}. Transaction may revert.`);
            }
        }

        this.logger.log({
            action: 'TRANSACTION_BUILT',
            contract: contractName,
            function: functionName,
            to: address,
            gasLimit: tx.gasLimit?.toString(),
            value: tx.value?.toString() || '0'
        });

        return tx;
    }

    // Send a transaction with confirmation
    async sendTransaction(contractName, functionName, params = [], overrides = {}) {
        // Rate limiting check
        if (!this.rateLimiter.canProceed()) {
            const waitTime = this.rateLimiter.getWaitTime();
            throw new Error(
                `Rate limit exceeded. Please wait ${Math.ceil(waitTime / 1000)} seconds.`
            );
        }

        // Simple nonce lock to prevent nonce conflicts
        if (this.nonceLock) {
            throw new Error('Another transaction is being processed. Please wait.');
        }

        this.nonceLock = true;

        try {
            const { contract, address } = this.getContract(contractName);

            // Validate function name
            if (!InputValidator.isValidFunctionName(functionName)) {
                throw new Error(`Invalid function name: ${functionName}`);
            }

            // Check function allowlist
            if (!this.allowlist.isFunctionAllowed(address, functionName)) {
                throw new Error(`Function "${functionName}" is not allowed`);
            }

            // Validate parameters
            const iface = contract.interface;
            const fragment = iface.getFunction(functionName);
            const validatedParams = this._validateParams(fragment.inputs, params);

            // Build overrides
            const txOverrides = this._buildOverrides(overrides);

            this.logger.log({
                action: 'TRANSACTION_SENDING',
                contract: contractName,
                function: functionName,
                params: validatedParams.map(p => p.toString()),
                from: this.walletManager.getAddress()
            });

            // Execute the contract function
            const tx = await contract[functionName](...validatedParams, txOverrides);

            this.logger.log({
                action: 'TRANSACTION_SENT',
                hash: tx.hash,
                nonce: tx.nonce,
                gasLimit: tx.gasLimit?.toString()
            });

            console.log(`Transaction sent: ${tx.hash}`);
            console.log('Waiting for confirmation...');

            // Wait for confirmation (1 block)
            const receipt = await tx.wait(1);

            this.logger.log({
                action: 'TRANSACTION_CONFIRMED',
                hash: receipt.transactionHash,
                blockNumber: receipt.blockNumber,
                gasUsed: receipt.gasUsed.toString(),
                status: receipt.status
            });

            if (receipt.status === 0) {
                throw new Error('Transaction reverted on-chain');
            }

            console.log(`Transaction confirmed in block ${receipt.blockNumber}`);
            return receipt;
        } finally {
            this.nonceLock = false;
        }
    }

    // Read-only call (no transaction, no gas)
    async callView(contractName, functionName, params = []) {
        const { contract, address } = this.getContract(contractName);

        if (!InputValidator.isValidFunctionName(functionName)) {
            throw new Error(`Invalid function name: ${functionName}`);
        }

        if (!this.allowlist.isFunctionAllowed(address, functionName)) {
            throw new Error(`Function "${functionName}" is not allowed`);
        }

        const iface = contract.interface;
        const fragment = iface.getFunction(functionName);

        if (!fragment.constant && fragment.stateMutability !== 'view' && fragment.stateMutability !== 'pure') {
            console.warn(`Warning: "${functionName}" is not a view/pure function. Using call anyway.`);
        }

        const validatedParams = this._validateParams(fragment.inputs, params);

        this.logger.log({
            action: 'VIEW_CALL',
            contract: contractName,
            function: functionName
        });

        const result = await contract.callStatic[functionName](...validatedParams);
        return result;
    }

    // Parse transaction events/logs
    parseTransactionLogs(contractName, receipt) {
        const { interface: iface } = this.getContract(contractName);
        const parsedLogs = [];

        for (const log of receipt.logs) {
            try {
                const parsed = iface.parseLog(log);
                parsedLogs.push({
                    name: parsed.name,
                    args: parsed.args,
                    signature: parsed.signature
                });
            } catch {
                // Log from a different contract, skip
            }
        }

        return parsedLogs;
    }

    // Validate parameters based on ABI types
    _validateParams(inputs, params) {
        return inputs.map((input, index) => {
            const param = params[index];
            const type = input.type;

            if (type === 'address') {
                if (!InputValidator.isValidAddress(param)) {
                    throw new Error(`Invalid address parameter at index ${index}: ${param}`);
                }
                return ethers.utils.getAddress(param); // Checksum address
            }

            if (type.startsWith('uint') || type.startsWith('int')) {
                if (!InputValidator.isValidUint256(param)) {
                    throw new Error(`Invalid numeric parameter at index ${index}: ${param}`);
                }
                return ethers.BigNumber.from(param);
            }

            if (type === 'bool') {
                if (typeof param !== 'boolean' && param !== 'true' && param !== 'false') {
                    throw new Error(`Invalid boolean parameter at index ${index}: ${param}`);
                }
                return param === true || param === 'true';
            }

            if (type === 'string') {
                return InputValidator.sanitizeString(String(param));
            }

            if (type === 'bytes' || type.match(/^bytes\d+$/)) {
                if (!/^0x[0-9a-fA-F]*$/.test(param)) {
                    throw new Error(`Invalid bytes parameter at index ${index}: ${param}`);
                }
                return param;
            }

            if (type.endsWith('[]')) {
                if (!Array.isArray(param)) {
                    throw new Error(`Expected array for parameter at index ${index}`);
                }
                // Limit array size to prevent gas griefing
                if (param.length > 100) {
                    throw new Error(`Array parameter at index ${index} exceeds maximum length of 100`);
                }
                return param;
            }

            // For tuple and other complex types, pass through
            return param;
        });
    }

    // Build transaction overrides with validation
    _buildOverrides(overrides) {
        const result = {};

        if (overrides.value) {
            if (!InputValidator.validateEtherValue(overrides.value)) {
                throw new Error(`Invalid ETH value: ${overrides.value}`);
            }
            result.value = ethers.utils.parseEther(overrides.value);
        }

        if (overrides.gasLimit) {
            const gasLimit = ethers.BigNumber.from(overrides.gasLimit);
            if (!InputValidator.validateGasLimit(gasLimit)) {
                throw new Error(`Invalid gas limit: ${overrides.gasLimit}`);
            }
            result.gasLimit = gasLimit;
        }

        if (overrides.gasPrice) {
            result.gasPrice = ethers.utils.parseUnits(overrides.gasPrice, 'gwei');
        }

        if (overrides.maxFeePerGas) {
            result.maxFeePerGas = ethers.utils.parseUnits(overrides.maxFeePerGas, 'gwei');
        }

        if (overrides.maxPriorityFeePerGas) {
            result.maxPriorityFeePerGas = ethers.utils.parseUnits(
                overrides.maxPriorityFeePerGas,
                'gwei'
            );
        }

        return result;
    }
}

// ============================================
// Interactive CLI for DApp Interaction
// ============================================

class DAppCLI {
    constructor() {
        this.rl = readline.createInterface({
            input: process.stdin,
            output: process.stdout
        });
        this.walletManager = null;
        this.contractManager = null;
        this.allowlist = new ContractAllowlist();
        this.logger = new TransactionLogger();
    }

    prompt(question) {
        return new Promise((resolve) => {
            this.rl.question(question, (answer) => {
                resolve(answer.trim());
            });
        });
    }

    async initialize() {
        console.log('========================================');
        console.log('  Secure DApp Smart Contract Interface  ');
        console.log('========================================\n');

        // Get provider URL
        const providerUrl = process.env.RPC_URL || await this.prompt('Enter RPC URL (or set RPC_URL env var): ');
        const chainId = process.env.CHAIN_ID || await this.prompt('Enter expected Chain ID (e.g., 1 for mainnet, 5 for goerli): ');

        try {
            this.walletManager = new WalletManager(providerUrl, chainId);
            await this.walletManager.connectFromEnvironment();

            this.contractManager = new ContractInteractionManager(
                this.walletManager,
                this.allowlist,
                this.logger
            );

            console.log('\nWallet connected successfully!\n');
        } catch (error) {
            console.error(`Initialization failed: ${error.message}`);
            process.exit(1);
        }
    }

    async setupDemoContracts() {
        // Example: ERC20 Token Contract
        const ERC20_ABI = [
            'function name() view returns (string)',
            'function symbol() view returns (string)',
            'function decimals() view returns (uint8)',
            'function totalSupply() view returns (uint256)',
            'function balanceOf(address owner) view returns (uint256)',
            'function transfer(address to, uint256 amount) returns (bool)',
            'function approve(address spender, uint256 amount) returns (bool)',
            'function allowance(address owner, address spender) view returns (uint256)',
            'function transferFrom(address from, address to, uint256 amount) returns (bool)',
            'event Transfer(address indexed from, address indexed to, uint256 value)',
            'event Approval(address indexed owner, address indexed spender, uint256 value)'
        ];

        console.log('\n--- Contract Setup ---');
        const setupContract = await this.prompt('Would you like to register a contract? (yes/no): ');

        if (setupContract.toLowerCase() === 'yes') {
            const contractAddress = await this.prompt('Enter contract address: ');

            if (!InputValidator.isValidAddress(contractAddress)) {
                console.error('Invalid contract address');
                return;
            }

            const contractName = InputValidator.sanitizeString(
                await this.prompt('Enter a name for this contract: ')
            );

            const useERC20 = await this.prompt('Use standard ERC20 ABI? (yes/no): ');

            // Add to allowlist first
            this.allowlist.addContract(contractAddress, contractName, [
                'name', 'symbol', 'decimals', 'totalSupply', 'balanceOf',
                'transfer', 'approve', 'allowance', 'transferFrom'
            ]);

            if (useERC20.toLowerCase() === 'yes') {
                this.contractManager.registerContract(contractName, contractAddress, ERC20_ABI);
            } else {
                const abiJson = await this.prompt('Enter contract ABI (JSON string): ');
                try {
                    const abi = JSON.parse(abiJson);
                    this.contractManager.registerContract(contractName, contractAddress, abi);
                } catch {
                    console.error('Invalid ABI JSON');
                    return;
                }
            }

            console.log(`Contract "${contractName}" registered successfully!`);
        }
    }

    async mainLoop() {
        while (true) {
            console.log('\n--- Main Menu ---');
            console.log('1. Register a new contract');
            console.log('2. Call a view function (read-only)');
            console.log('3. Send a transaction');
            console.log('4. Build transaction (preview without sending)');
            console.log('5. View transaction logs');
            console.log('6. Check wallet balance');
            console.log('7. Exit');

            const choice = await this.prompt('\nSelect an option (1-7): ');

            try {
                switch (choice) {
                    case '1':
                        await this.setupDemoContracts();
                        break;
                    case '2':
                        await this.handleViewCall();
                        break;
                    case '3':
                        await this.handleSendTransaction();
                        break;
                    case '4':
                        await this.handleBuildTransaction();
                        break;
                    case '5':
                        this.viewLogs();
                        break;
                    case '6':
                        await this.checkBalance();
                        break;
                    case '7':
                        console.log('Goodbye!');
                        this.rl.close();
                        return;
                    default:
                        console.log('Invalid option');
                }
            } catch (error) {
                console.error(`Error: ${error.message}`);
            }
        }
    }

    async handleViewCall() {
        const contractName = await this.prompt('Contract name: ');
        const functionName = await this.prompt('Function name: ');
        const paramCount = parseInt(await this.prompt('Number of parameters: '), 10);

        const params = [];
        for (let i = 0; i < paramCount; i++) {
            const param = await this.prompt(`Parameter ${i + 1}: `);
            params.push(param);
        }

        console.log('\nCalling view function...');
        const result = await this.contractManager.callView(contractName, functionName, params);
        console.log(`\nResult: ${result}`);
    }

    async handleSendTransaction() {
        const contractName = await this.prompt('Contract name: ');
        const functionName = await this.prompt('Function name: ');
        const paramCount = parseInt(await this.prompt('Number of parameters: '), 10);

        if (isNaN(paramCount) || paramCount < 0 || paramCount > 20) {
            throw new Error('Invalid parameter count (0-20)');
        }

        const params = [];
        for (let i = 0; i < paramCount; i++) {
            const param = await this.prompt(`Parameter ${i + 1}: `);
            params.push(param);
        }

        // Collect overrides
        const overrides = {};
        const sendValue = await this.prompt('ETH value to send (0 for none): ');
        if (sendValue && sendValue !== '0') {
            overrides.value = sendValue;
        }

        const customGas = await this.prompt('Custom gas limit (press Enter for auto): ');
        if (customGas) {
            overrides.gasLimit = customGas;
        }

        // Transaction preview and confirmation
        console.log('\n--- Transaction Preview ---');
        console.log(`Contract: ${contractName}`);
        console.log(`Function: ${functionName}`);
        console.log(`Parameters: ${JSON.stringify(params)}`);
        console.log(`Value: ${overrides.value || '0'} ETH`);
        console.log(`Gas Limit: ${overrides.gasLimit || 'auto'}`);
        console.log(`From: ${this.walletManager.getAddress()}`);

        // SECURITY: Require explicit user confirmation before signing
        const confirm = await this.prompt('\nConfirm transaction? Type "CONFIRM" to proceed: ');

        if (confirm !== 'CONFIRM') {
            console.log('Transaction cancelled by user.');
            return;
        }

        console.log('\nSending transaction...');
        const receipt = await this.contractManager.sendTransaction(
            contractName,
            functionName,
            params,
            overrides
        );

        console.log('\n--- Transaction Receipt ---');
        console.log(`Hash: ${receipt.transactionHash}`);
        console.log(`Block: ${receipt.blockNumber}`);
        console.log(`Gas Used: ${receipt.gasUsed.toString()}`);
        console.log(`Status: ${receipt.status === 1 ? 'Success' : 'Failed'}`);

        // Parse and display events
        const events = this.contractManager.parseTransactionLogs(contractName, receipt);
        if (events.length > 0) {
            console.log('\n--- Events ---');
            events.forEach((event, i) => {
                console.log(`Event ${i + 1}: ${event.name}`);
                console.log(`  Signature: ${event.signature}`);
            });
        }
    }

    async handleBuildTransaction() {
        const contractName = await this.prompt('Contract name: ');
        const functionName = await this.prompt('Function name: ');
        const paramCount = parseInt(await this.prompt('Number of parameters: '), 10);

        if (isNaN(paramCount) || paramCount < 0 || paramCount > 20) {
            throw new Error('Invalid parameter count (0-20)');
        }

        const params = [];
        for (let i = 0; i < paramCount; i++) {
            const param = await this.prompt(`Parameter ${i + 1}: `);
            params.push(param);
        }

        const overrides = {};
        const sendValue = await this.prompt('ETH value to send (0 for none): ');
        if (sendValue && sendValue !== '0') {
            overrides.value = sendValue;
        }

        console.log('\nBuilding transaction (not sending)...');
        const tx = await this.contractManager.buildTransaction(
            contractName,
            functionName,
            params,
            overrides
        );

        console.log('\n--- Built Transaction ---');
        console.log(`To: ${tx.to}`);
        console.log(`Data: ${tx.data}`);
        console.log(`Value: ${tx.value?.toString() || '0'}`);
        console.log(`Gas Limit: ${tx.gasLimit?.toString() || 'not set'}`);
        console.log('\nThis transaction was NOT sent. Use option 3 to send.');
    }

    viewLogs() {
        const logs = this.logger.getLogs();
        if (logs.length === 0) {
            console.log('No transaction logs yet.');
            return;
        }

        console.log('\n--- Transaction Logs ---');
        logs.forEach((log, i) => {
            console.log(`\n[${i + 1}] ${log.timestamp} - ${log.action}`);
            Object.entries(log).forEach(([key, value]) => {
                if (key !== 'timestamp' && key !== 'action') {
                    console.log(`  ${key}: ${value}`);
                }
            });
        });
    }

    async checkBalance() {
        const address = this.walletManager.getAddress();
        const balance = await this.walletManager.provider.getBalance(address);
        console.log(`\nWallet: ${address}`);
        console.log(`Balance: ${ethers.utils.formatEther(balance)} ETH`);
    }
}

// ============================================
// Programmatic API (for integration)
// ============================================

class DAppAPI {
    constructor(config) {
        this.config = config;
        this.logger = new TransactionLogger();
        this.allowlist = new ContractAllowlist();
    }

    async initialize() {
        this.walletManager = new WalletManager(
            this.config.providerUrl,
            this.config.chainId
        );

        if (this.config.browserProvider) {
            await this.walletManager.connectBrowserWallet(this.config.browserProvider);
        } else {
            await this.walletManager.connectFromEnvironment();
        }

        this.contractManager = new ContractInteractionManager(
            this.walletManager,
            this.allowlist,
            this.logger
        );

        return this;
    }

    addAllowedContract(address, name, allowedFunctions = []) {
        this.allowlist.addContract(address, name, allowedFunctions);
    }

    registerContract(name, address, abi) {
        return this.contractManager.registerContract(name, address, abi);
    }

    async read(contractName, functionName, params = []) {
        return this.contractManager.callView(contractName, functionName, params);
    }

    async write(contractName, functionName, params = [], overrides = {}) {
        return this.contractManager.sendTransaction(contractName, functionName, params, overrides);
    }

    async buildTx(contractName, functionName, params = [], overrides = {}) {
        return this.contractManager.buildTransaction(contractName, functionName, params, overrides);
    }

    getLogs() {
        return this.logger.getLogs();
    }
}

// ============================================
// Main Entry Point
// ============================================

async function main() {
    const cli = new DAppCLI();

    try {
        await cli.initialize();
        await cli.setupDemoContracts();
        await cli.mainLoop();
    } catch (error) {
        console.error(`Fatal error: ${error.message}`);
        process.exit(1);
    }
}

// Run CLI if executed directly
if (require.main === module) {
    main().catch(console.error);
}

// Export modules for programmatic use
module.exports = {
    DAppAPI,
    DAppCLI,
    WalletManager,
    ContractInteractionManager,
    ContractAllowlist,
    InputValidator,
    TransactionLogger,
    RateLimiter
};